import React from 'react';
import styled from 'styled-components';

const SkillsSection = () => {
  return (
    <Container>
        <Title>👨‍💻Skills</Title>
        <SectionList>
          <ListItem>🖥️Languages: Python, SQL, MATLAB, C/C++</ListItem>
          <ListItem>🛠️Tools: MS Excel, VS Code, GitHub, AWS, Azure, GCP, PowerBI</ListItem>
          <ListItem>🌐Frameworks: Django, Flask, React</ListItem>
          <ListItem>🗣Soft Skills: Public Speaking, Leadership, Event Management</ListItem>
        </SectionList>
    </Container>
  );
};

export default SkillsSection;
